EXCEL = os.path.join(BASE, 'PM_ESTUDIO_MASTER_COMPLETO.xlsx')
OUT = os.path.join(BASE, 'docs', 'index.html')

wb = openpyxl.load_workbook(EXCEL, data_only=True)
